module RefModule(
    input clk,
    input reset,
    input enable,
    output reg [2:0] count
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 3'd0;
        else if (enable)
            count <= count + 1;
    end
endmodule
